// src/data/index.js
import wordsData from './words.json';

// For development, we'll use the combined file
// In production, this will be generated by the build script
import sentencesData from './sentences.json';

export const loadWords = async () => {
    return wordsData;
};

export const loadSentences = async () => {
    return sentencesData;
};

// Optional: If you want to load levels dynamically
export const loadLevels = async () => {
    // You could also read the level files directly here
    const levelFiles = require.context('./levels', false, /\.json$/);
    const levels = [];

    levelFiles.keys().forEach(key => {
        const levelData = levelFiles(key);
        levels.push({
            id: levelData.level,
            name: levelData.name,
            description: levelData.description,
            icon: levelData.icon
        });
    });

    return levels.sort((a, b) => a.id - b.id);
};